=Please analyze this maintenance request and return ONLY a JSON object with exactly these fields — no extra text, no markdown:

{
  "category": "Emergency" or "Routine" or "Needs Review",
  "priority": "High" or "Normal" or "Review",
  "summary": "A clear 1-2 sentence summary of the issue",
  "property_address": "The property address from the request",
  "tenant_name": "The tenant name from the request",
  "recommended_action": "What should be done next",
  "missing_info": null or "what is missing"
}

Tenant Name: {{ $('Webhook').item.json.body.tenant_name }}
Property Address: {{ $('Webhook').item.json.body.property_address }}
Issue Description: {{ $('Webhook').item.json.body.issue_description }}
Submitted At: {{ $('Webhook').item.json.body.submitted_at }}

parameters.jsCode:
// ============================================================
// GreenLeaf Property Management — AI Response Parser
// Custom business logic for maintenance request triage
// ============================================================

const inputData = $input.first().json;

// Extract AI response from n8n OpenAI node output structure
const aiResponse = 
  inputData?.output?.[0]?.content?.[0]?.text ||     // confirmed path
  inputData?.message?.content ||                     // fallback 1
  inputData?.text ||                                 // fallback 2
  inputData?.choices?.[0]?.message?.content ||       // fallback 3
  null;

// ── EDGE CASE: AI response unreadable ──────────────────────
if (!aiResponse) {
  return [{
    json: {
      category: "Needs Review",
      priority: "Review",
      summary: "Could not read AI response — manual review needed",
      property_address: $('Webhook').item.json.body.property_address || "Unknown",
      tenant_name: $('Webhook').item.json.body.tenant_name || "Unknown",
      recommended_action: "Flag for human coordinator review",
      missing_info: "AI response structure unrecognized",
      contact_email: $('Webhook').item.json.body.contact_email || "Unknown",
      sla_hours: 24,
      escalate: true,
      timestamp: new Date().toISOString(),
      formatted_date: new Date().toLocaleDateString('en-US', {
        year: 'numeric', month: 'long', day: 'numeric',
        hour: '2-digit', minute: '2-digit'
      })
    }
  }];
}

// ── CLEAN AI RESPONSE ──────────────────────────────────────
const cleaned = aiResponse
  .replace(/```json/g, '')
  .replace(/```/g, '')
  .trim();

// ── PARSE JSON ─────────────────────────────────────────────
let parsed;
try {
  parsed = JSON.parse(cleaned);
} catch (error) {
  parsed = {
    category: "Needs Review",
    priority: "Review",
    summary: "Could not parse AI response — manual review needed",
    property_address: $('Webhook').item.json.body.property_address || "Unknown",
    tenant_name: $('Webhook').item.json.body.tenant_name || "Unknown",
    recommended_action: "Flag for human coordinator review",
    missing_info: "AI response was malformed: " + aiResponse
  };
}

// ── BUSINESS LOGIC: SLA RULES ──────────────────────────────
// Automatically assign SLA response times based on category
// Emergency = 2 hours, Routine = 48 hours, Review = 24 hours
const slaMap = {
  "Emergency": 2,
  "Routine": 48,
  "Needs Review": 24
};

parsed.sla_hours = slaMap[parsed.category] || 24;

// ── BUSINESS LOGIC: SLA DEADLINE ──────────────────────────
// Calculate the exact deadline timestamp for this request
const now = new Date();
const deadline = new Date(now.getTime() + parsed.sla_hours * 60 * 60 * 1000);
parsed.sla_deadline = deadline.toLocaleDateString('en-US', {
  year: 'numeric', month: 'long', day: 'numeric',
  hour: '2-digit', minute: '2-digit'
});

// ── BUSINESS LOGIC: ESCALATION FLAG ───────────────────────
// Flag anything that needs immediate human attention
parsed.escalate = parsed.category === "Emergency" || 
                  parsed.category === "Needs Review";

// ── BUSINESS LOGIC: PRIORITY SCORE ────────────────────────
// Numeric score for sorting/filtering in Google Sheets
const priorityScore = {
  "Emergency": 1,
  "Routine": 2,
  "Needs Review": 3
};
parsed.priority_score = priorityScore[parsed.category] || 3;

// ── ADD TENANT CONTACT DETAILS ─────────────────────────────
parsed.contact_email = $('Webhook').item.json.body.contact_email || "Unknown";

// ── ADD TIMESTAMPS ─────────────────────────────────────────
parsed.timestamp = now.toISOString();
parsed.formatted_date = now.toLocaleDateString('en-US', {
  year: 'numeric', month: 'long', day: 'numeric',
  hour: '2-digit', minute: '2-digit'
});

return [{ json: parsed }];
